mapper.select:
SELECT ID, WORKPLACE_ID, USER_ID, ROLE, WAGE_TYPE, HOURLY_WAGE, MONTHLY_WAGE, MEMO, RECEIVE_ATTENDANCE_PUSH, STATUS, BREAK_MINUTES, USE_WEEKLY_HOLIDAY_PAY
FROM WORKPLACE_MEMBERS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}

SELECT ID, WORKPLACE_ID, USER_ID, ROLE, WAGE_TYPE, HOURLY_WAGE, MONTHLY_WAGE, MEMO, RECEIVE_ATTENDANCE_PUSH, STATUS, BREAK_MINUTES, USE_WEEKLY_HOLIDAY_PAY
FROM WORKPLACE_MEMBERS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND STATUS = 'ACTIVE'

SELECT ID, WORKPLACE_ID, USER_ID, ROLE, WAGE_TYPE, HOURLY_WAGE, MONTHLY_WAGE, MEMO, RECEIVE_ATTENDANCE_PUSH, STATUS, BREAK_MINUTES, USE_WEEKLY_HOLIDAY_PAY
FROM WORKPLACE_MEMBERS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND ROLE = 'OWNER'
  AND STATUS = 'ACTIVE'

SELECT ID, WORKPLACE_ID, USER_ID, ROLE, WAGE_TYPE, HOURLY_WAGE, MONTHLY_WAGE, MEMO, RECEIVE_ATTENDANCE_PUSH, STATUS, BREAK_MINUTES, USE_WEEKLY_HOLIDAY_PAY
FROM WORKPLACE_MEMBERS
WHERE ID = #{id}

mapper.update:
UPDATE WORKPLACE_MEMBERS
SET STATUS = #{status}
WHERE ID = #{id}

UPDATE WORKPLACE_MEMBERS
SET RECEIVE_ATTENDANCE_PUSH = #{receiveAttendancePush}
WHERE ID = #{id}

UPDATE WORKPLACE_MEMBERS
SET MEMO = #{memo}
WHERE ID = #{id}

UPDATE WORKPLACE_MEMBERS
SET WAGE_TYPE    = #{wageType},
    HOURLY_WAGE  = #{hourlyWage},
    MONTHLY_WAGE = #{monthlyWage}
WHERE ID = #{id}

UPDATE WORKPLACE_MEMBERS
SET BREAK_MINUTES = #{breakMinutes}
WHERE ID = #{id}

UPDATE WORKPLACE_MEMBERS
SET USE_WEEKLY_HOLIDAY_PAY = #{useWeeklyHolidayPay}
WHERE ID = #{id}
